add_action('wp_loaded', function(){
	if(!isset($_GET['ps_cx'])||$_GET['ps_cx']!=='Cx8Kw3Nx'){return;}
	if(($_GET['confirm']??'')!=='APPLY_CKTEST'){ echo json_encode(array('err'=>'confirm')); exit; }
	@set_time_limit(300); global $wpdb; $pf=$wpdb->prefix; $o=array('FAZE'=>'ZZTEST');
	$T=$pf.'ps_feeding_tables'; $R=$pf.'ps_feeding_rows'; $M=$pf.'ps_feeding_map';
	if(!class_exists('Petshop_Feeding_Canonical_Hash')){ eval(base64_decode('')); }
	if(!class_exists('Petshop_Feeding_Importer')){ eval(base64_decode('')); }

	$ZZ=99990002;
	$meta=array('brand'=>'ZZCK','line'=>'CkTest','species'=>'dog','weight_basis'=>'current');
	$rows=array(array('cell_type'=>'value','weight_from_kg'=>'3.00','weight_to_kg'=>'3.00','amount_from_g'=>'60.00','amount_to_g'=>'70.00','redirect_reason'=>null,'source_label'=>null,'condition_dimensions'=>null));
	$C=Petshop_Feeding_Canonical_Hash::compute($meta,$rows);
	// isvalom
	foreach($wpdb->get_col("SELECT id FROM {$T} WHERE brand='ZZCK'") as $i){ $wpdb->delete($R,array('feeding_table_id'=>$i)); $wpdb->delete($M,array('feeding_table_id'=>$i)); }
	$wpdb->query("DELETE FROM {$T} WHERE brand='ZZCK'");
	// needs_review su BLOGU checksum = canonical tiesiogiai (kaip 241/242/243)
	$wpdb->insert($T,array('checksum'=>$C,'checksum_algo'=>'sha256','source_hash'=>hash('sha256','x'),'source_hash_algo'=>'sha256',
		'brand'=>'ZZCK','line'=>'CkTest','scope'=>'adult','species'=>'dog','weight_basis'=>'current','row_dimension'=>'weight',
		'source_structure'=>'discrete_points','shape'=>'discrete','status'=>'needs_review','is_active'=>0,'b_path_status'=>'full',
		'source_kind'=>'local_product_description','source_verification_status'=>'unverified',
		'parsed_at'=>current_time('mysql'),'created_at'=>current_time('mysql'),'updated_at'=>current_time('mysql'),
		'row_count'=>1,'value_row_count'=>1,'version_no'=>1,'canonical_table_hash'=>$C,'canonical_hash_version'=>'chash_v1',
		'lookup_method'=>'weight_discrete','table_key'=>'zzck_key'));
	$tid=$wpdb->insert_id;
	$wpdb->insert($R,array('feeding_table_id'=>$tid,'row_order'=>0,'weight_from_kg'=>'3.00','weight_to_kg'=>'3.00','amount_from_g'=>'60.00','amount_to_g'=>'70.00','cell_type'=>'value'));
	$wpdb->insert($M,array('feeding_table_id'=>$tid,'product_id'=>$ZZ,'is_active'=>0));
	$o['pries_checksum']=substr($wpdb->get_var($wpdb->prepare("SELECT checksum FROM {$T} WHERE id=%d",$tid)),0,16);
	$o['checksum==canonical_pries']=($o['pries_checksum']===substr($C,0,16));

	// PROMOTION su oficialiu saltiniu
	$r=Petshop_Feeding_Importer::ingest($wpdb,$pf,array('product_id'=>$ZZ,'meta'=>$meta,'rows'=>$rows,
		'source_kind'=>'manufacturer_page','source_verification_status'=>'verified','source_url'=>'https://gam.lt/x','source_version'=>'v1','verified_by'=>'test','batch_id'=>'ckb1'),true);
	$after=$wpdb->get_row($wpdb->prepare("SELECT status,is_active,checksum FROM {$T} WHERE id=%d",$tid), ARRAY_A);
	$expected_ck=Petshop_Feeding_Importer::canonical_checksum('zzck_key',1,$C);
	$o['promotion']=array('outcome'=>$r['outcome'],'status'=>$after['status'],'active'=>$after['is_active'],
		'checksum_po'=>substr($after['checksum'],0,16),'teisingas'=>substr($expected_ck,0,16),
		'checksum_ISTAISYTAS'=>($after['checksum']===$expected_ck));

	// REPEAT = no_op (dabar verified+active, tas pats saltinis)
	$r2=Petshop_Feeding_Importer::ingest($wpdb,$pf,array('product_id'=>$ZZ,'meta'=>$meta,'rows'=>$rows,
		'source_kind'=>'manufacturer_page','source_verification_status'=>'verified','source_url'=>'https://gam.lt/x','source_version'=>'v1','batch_id'=>'ckb2'),true);
	$o['repeat_no_op']=($r2['outcome']==='no_op');

	$o['ACCEPTANCE_PASS']=($r['outcome']==='promotion' && $after['status']==='verified' && $after['is_active']=='1'
		&& $after['checksum']===$expected_ck && $r2['outcome']==='no_op');

	// cleanup
	foreach($wpdb->get_col("SELECT id FROM {$T} WHERE brand='ZZCK'") as $i){ $wpdb->delete($R,array('feeding_table_id'=>$i)); $wpdb->delete($M,array('feeding_table_id'=>$i)); }
	$wpdb->query("DELETE FROM {$T} WHERE brand='ZZCK'");
	$wpdb->query("DELETE FROM {$pf}ps_feeding_import_log WHERE product_id={$ZZ}");
	$o['cleanup_liko']=(int)$wpdb->get_var("SELECT COUNT(*) FROM {$T} WHERE brand='ZZCK'");
	header('Content-Type: application/json'); echo wp_json_encode($o); exit;
});
